function load$TaxIncome$(g) {
  g.add_itemValueChanged(onChange$TaxIncome$);
  g.add_commandEvent(on$TaxIncome$ExecuteCommand);
  g.$a = {ho_tro_bh: '[ho_tro_bh]:=0', '[loai_tn] == 0']};
}
function dispose$TaxIncome$(g) {
  try {g.remove_commandEvent(on$TaxIncome$ExecuteCommand);} catch (ex) {}
  try {g.remove_itemValueChanged(onChange$TaxIncome$);} catch (ex) {}
}
function on$TaxIncome$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = g.get_element().parentForm, g = f.getItem('d3')._controlBehavior;
	switch (action) {
    case 'AfterCloneRow':
      g.setItemFieldValue('stt_rec0', e.type.Value, '');
      break;
    default:
      break;
  }
}
function onChange$TaxIncome$(sender, eventArgs) {
  var o = eventArgs.get_object(), g = o.grid, f = g.get_element().parentForm, name = o.field.Name;
  switch (name) {
    case 'loai_tn':
      g.executeExpression(o, [g.$a.ho_tro_bh]);
      break;
    default:
      break;
  }
}








